"""
Measure-by-measure MusicXML diagnostic comparison.

Compares ground truth and output MusicXML with structural awareness:
- Per-measure, per-staff comparison (not flat sequence)
- Voice-agnostic matching (ignores voice numbering differences)
- Coverage detection (only scores overlapping measures)
- Error pattern classification (octave, accidental, step, rhythm, wild)

Usage:
    python -m validation.diagnose_musicxml <ground_truth.xml> <output.musicxml>
"""

import sys
import xml.etree.ElementTree as ET
from dataclasses import dataclass, field
from difflib import SequenceMatcher


@dataclass
class NoteInfo:
    pitch: str  # "C4", "D#5", "rest"
    note_type: str  # "quarter", "eighth."
    is_chord: bool = False

    def key(self) -> str:
        return f"{self.pitch}:{self.note_type}"


@dataclass
class MeasureNotes:
    measure_num: int
    notes_by_staff: dict[int, list[NoteInfo]] = field(default_factory=dict)


@dataclass
class ErrorInfo:
    measure: int
    staff: int
    category: str  # "missing", "extra", "octave", "accidental", "step", "rhythm",
    # "rest_note_swap", "cross_staff", "far_pitch"
    detail: str


def _parse_pitch(pitch_elem: ET.Element, ns: str) -> str:
    step = pitch_elem.find(f"{ns}step")
    octave = pitch_elem.find(f"{ns}octave")
    alter = pitch_elem.find(f"{ns}alter")
    step_text = step.text if step is not None else "?"
    octave_text = octave.text if octave is not None else "?"
    alter_text = ""
    if alter is not None:
        a = int(float(alter.text))  # type: ignore[arg-type]
        if a == 1:
            alter_text = "#"
        elif a == -1:
            alter_text = "b"
        elif a == 2:
            alter_text = "##"
        elif a == -2:
            alter_text = "bb"
    return f"{step_text}{alter_text}{octave_text}"


def extract_measures(xml_path: str) -> list[MeasureNotes]:
    """Extract notes grouped by measure and staff from a MusicXML file."""
    tree = ET.parse(xml_path)  # noqa: S314
    root = tree.getroot()

    ns = ""
    if root.tag.startswith("{"):
        ns = root.tag.split("}")[0] + "}"

    measures: dict[int, MeasureNotes] = {}

    for part in root.iter(f"{ns}part"):
        for measure_elem in part.iter(f"{ns}measure"):
            num_str = measure_elem.get("number", "0")
            try:
                num = int(num_str)
            except ValueError:
                # Some MusicXML files use non-numeric measure numbers like "X1"
                num = int("".join(c for c in num_str if c.isdigit()) or "0")

            if num not in measures:
                measures[num] = MeasureNotes(measure_num=num)

            for note_elem in measure_elem.iter(f"{ns}note"):
                # Skip grace notes
                if note_elem.find(f"{ns}grace") is not None:
                    continue

                type_elem = note_elem.find(f"{ns}type")
                note_type: str = type_elem.text if type_elem is not None and type_elem.text else "?"

                dots = len(note_elem.findall(f"{ns}dot"))
                if dots == 1:
                    note_type += "."
                elif dots == 2:
                    note_type += ".."

                staff_elem = note_elem.find(f"{ns}staff")
                staff_num = (
                    int(staff_elem.text) if staff_elem is not None and staff_elem.text else 1
                )

                is_chord = note_elem.find(f"{ns}chord") is not None

                if note_elem.find(f"{ns}rest") is not None:
                    pitch = "rest"
                else:
                    pitch_elem = note_elem.find(f"{ns}pitch")
                    if pitch_elem is not None:
                        pitch = _parse_pitch(pitch_elem, ns)
                    else:
                        continue

                note = NoteInfo(pitch=pitch, note_type=note_type, is_chord=is_chord)
                if staff_num not in measures[num].notes_by_staff:
                    measures[num].notes_by_staff[staff_num] = []
                measures[num].notes_by_staff[staff_num].append(note)

    return [measures[k] for k in sorted(measures.keys())]


def _split_pitch(pitch_str: str) -> tuple[str, str, str]:
    """Split 'C#4' into ('C', '#', '4'). Returns (letter, accidental, octave)."""
    if pitch_str == "rest":
        return ("rest", "", "")
    letter = pitch_str[0]
    rest = pitch_str[1:]
    accidental = ""
    for acc in ("##", "bb", "#", "b"):
        if rest.startswith(acc):
            accidental = acc
            rest = rest[len(acc) :]
            break
    return (letter, accidental, rest)


# Semitone values for pitch comparison
_NOTE_SEMITONES = {"C": 0, "D": 2, "E": 4, "F": 5, "G": 7, "A": 9, "B": 11}
_ACC_SEMITONES = {"": 0, "#": 1, "b": -1, "##": 2, "bb": -2}


def _pitch_to_midi(pitch_str: str) -> int | None:
    """Convert pitch string to MIDI-like number for interval comparison."""
    if pitch_str == "rest":
        return None
    letter, acc, octave = _split_pitch(pitch_str)
    if letter not in _NOTE_SEMITONES or octave == "" or not octave.isdigit():
        return None
    return int(octave) * 12 + _NOTE_SEMITONES[letter] + _ACC_SEMITONES.get(acc, 0)


def classify_substitution(  # noqa: PLR0911
    gt_pitch: str, out_pitch: str, gt_type: str, out_type: str
) -> str:
    """Classify a substitution error into a category."""
    pitch_same = gt_pitch == out_pitch
    type_same = gt_type == out_type

    if pitch_same:
        return "match" if type_same else "rhythm"

    gt_letter, gt_acc, gt_oct = _split_pitch(gt_pitch)
    out_letter, out_acc, out_oct = _split_pitch(out_pitch)

    # Rest vs note
    if gt_pitch == "rest" or out_pitch == "rest":
        return "rest_note_swap"

    # Same letter checks
    if gt_letter == out_letter:
        if gt_acc == out_acc and gt_oct != out_oct:
            return "octave"
        if gt_oct == out_oct and gt_acc != out_acc:
            gt_midi = _pitch_to_midi(gt_pitch)
            out_midi = _pitch_to_midi(out_pitch)
            if gt_midi is not None and out_midi is not None and gt_midi == out_midi:
                return "enharmonic"
            return "accidental"

    # Step error: adjacent semitone (within 2 semitones)
    gt_midi = _pitch_to_midi(gt_pitch)
    out_midi = _pitch_to_midi(out_pitch)
    if gt_midi is not None and out_midi is not None and abs(gt_midi - out_midi) <= 2:
        return "step"

    # Cross-staff: large interval (>= 12 semitones = octave+) likely from wrong staff
    if gt_midi is not None and out_midi is not None and abs(gt_midi - out_midi) >= 12:
        return "cross_staff"

    return "far_pitch"


def compare_measure_staff(
    gt_notes: list[NoteInfo],
    out_notes: list[NoteInfo],
    measure_num: int,
    staff_num: int,
) -> list[ErrorInfo]:
    """Compare notes for one measure+staff, voice-agnostic."""
    # Sort by pitch then type for consistent ordering (voice-agnostic)
    gt_keys = sorted([n.key() for n in gt_notes])
    out_keys = sorted([n.key() for n in out_notes])

    if gt_keys == out_keys:
        return []

    errors: list[ErrorInfo] = []
    matcher = SequenceMatcher(None, gt_keys, out_keys)

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == "equal":
            continue
        elif tag == "replace":
            # Pair up substitutions
            gt_span = gt_keys[i1:i2]
            out_span = out_keys[j1:j2]
            for k in range(max(len(gt_span), len(out_span))):
                if k < len(gt_span) and k < len(out_span):
                    gp, gt_ = gt_span[k].split(":")
                    op, ot = out_span[k].split(":")
                    cat = classify_substitution(gp, op, gt_, ot)
                    if cat == "rhythm":
                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    else:
                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    errors.append(ErrorInfo(measure_num, staff_num, cat, detail))
                elif k < len(gt_span):
                    errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_span[k]))
                else:
                    errors.append(ErrorInfo(measure_num, staff_num, "extra", out_span[k]))
        elif tag == "delete":
            for k in range(i1, i2):
                errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_keys[k]))
        elif tag == "insert":
            for k in range(j1, j2):
                errors.append(ErrorInfo(measure_num, staff_num, "extra", out_keys[k]))

    return errors


def diagnose(gt_path: str, out_path: str) -> None:
    """Run full diagnostic comparison and print results."""
    gt_measures = extract_measures(gt_path)
    out_measures = extract_measures(out_path)

    gt_nums = {m.measure_num for m in gt_measures}
    out_nums = {m.measure_num for m in out_measures}
    overlap = sorted(gt_nums & out_nums)

    # --- Section 1: Coverage ---
    print("=" * 60)
    print("COVERAGE")
    print("=" * 60)
    if gt_nums:
        gt_range = f"{min(gt_nums)}-{max(gt_nums)}"
    else:
        gt_range = "(none)"
    if out_nums:
        out_range = f"{min(out_nums)}-{max(out_nums)}"
    else:
        out_range = "(none)"
    print(f"  Ground truth:  {len(gt_nums)} measures ({gt_range})")
    print(f"  Output:        {len(out_nums)} measures ({out_range})")
    print(f"  Overlap:       {len(overlap)} measures")
    if gt_nums:
        pct = 100 * len(overlap) / len(gt_nums)
        print(f"  Coverage:      {pct:.0f}%")
    print()

    if not overlap:
        print("No overlapping measures to compare.")
        return

    # Build lookup dicts
    gt_by_num = {m.measure_num: m for m in gt_measures}
    out_by_num = {m.measure_num: m for m in out_measures}

    # Collect all staves across both files
    all_staves: set[int] = set()
    for num in overlap:
        all_staves.update(gt_by_num[num].notes_by_staff.keys())
        all_staves.update(out_by_num[num].notes_by_staff.keys())

    # --- Section 2: Measure-by-measure diffs ---
    print("=" * 60)
    print("MEASURE-BY-MEASURE DIFFS (errors only)")
    print("=" * 60)

    all_errors: list[ErrorInfo] = []
    perfect_measures = 0
    compared_measures = 0

    for num in overlap:
        gt_m = gt_by_num[num]
        out_m = out_by_num[num]
        measure_errors: list[ErrorInfo] = []

        staves = sorted(set(gt_m.notes_by_staff.keys()) | set(out_m.notes_by_staff.keys()))
        for staff in staves:
            gt_notes = gt_m.notes_by_staff.get(staff, [])
            out_notes = out_m.notes_by_staff.get(staff, [])
            errs = compare_measure_staff(gt_notes, out_notes, num, staff)
            measure_errors.extend(errs)

        compared_measures += 1
        if not measure_errors:
            perfect_measures += 1
        else:
            all_errors.extend(measure_errors)
            # Print this measure's diff
            print(f"\nM{num}:")
            for staff in staves:
                gt_notes = gt_m.notes_by_staff.get(staff, [])
                out_notes = out_m.notes_by_staff.get(staff, [])
                staff_errs = [e for e in measure_errors if e.staff == staff]
                if not staff_errs:
                    continue
                gt_str = " ".join(sorted(n.key() for n in gt_notes))
                out_str = " ".join(sorted(n.key() for n in out_notes))
                if len(staves) > 1:
                    print(f"  Staff {staff}:")
                    prefix = "    "
                else:
                    prefix = "  "
                print(f"{prefix}GT:  {gt_str}")
                print(f"{prefix}Out: {out_str}")
                for e in staff_errs:
                    label = e.category.upper()
                    print(f"{prefix}  - {label}: {e.detail}")

    if not all_errors:
        print("\n  (all measures match perfectly)")

    # --- Section 3: Aggregate summary ---
    print()
    print("=" * 60)
    print("ERROR SUMMARY (covered measures only)")
    print("=" * 60)
    print(f"  Perfect measures: {perfect_measures}/{compared_measures}", end="")
    if compared_measures > 0:
        print(f" ({100 * perfect_measures / compared_measures:.0f}%)")
    else:
        print()

    if not all_errors:
        print("  No errors found!")
        return

    # Count by category
    categories = [
        "missing",
        "extra",
        "octave",
        "accidental",
        "enharmonic",
        "step",
        "rhythm",
        "rest_note_swap",
        "cross_staff",
        "far_pitch",
    ]
    counts: dict[str, int] = dict.fromkeys(categories, 0)
    for e in all_errors:
        counts[e.category] = counts.get(e.category, 0) + 1

    total_errors = len(all_errors)
    print(f"\n  Total errors: {total_errors}")
    print()
    print(f"  {'Category':<20} {'Count':>5}  {'%':>5}")
    print(f"  {'-' * 20} {'-' * 5}  {'-' * 5}")
    for cat in categories:
        count = counts[cat]
        if count > 0:
            pct = 100 * count / total_errors
            print(f"  {cat:<20} {count:>5}  {pct:>4.0f}%")

    # Show which measures have the most errors
    measure_error_counts: dict[int, int] = {}
    for e in all_errors:
        measure_error_counts[e.measure] = measure_error_counts.get(e.measure, 0) + 1
    worst = sorted(measure_error_counts.items(), key=lambda x: -x[1])[:10]
    if worst:
        print("\n  Worst measures:")
        for mnum, cnt in worst:
            print(f"    M{mnum}: {cnt} errors")


@dataclass
class DiagnosisResult:
    """Structured diagnosis output for programmatic use."""

    errors: list[ErrorInfo]
    perfect_measures: int
    total_measures: int
    error_counts: dict[str, int]
    per_staff_errors: dict[int, int]
    duration_check: dict[str, int]  # {"ok": N, "underfull": N, "overfull": N}


# Duration fractions for MusicXML <type> values
_TYPE_FRACTIONS: dict[str, float] = {
    "maxima": 8.0,
    "long": 4.0,
    "breve": 2.0,
    "whole": 1.0,
    "half": 0.5,
    "quarter": 0.25,
    "eighth": 0.125,
    "16th": 0.0625,
    "32nd": 0.03125,
    "64th": 0.015625,
    "128th": 0.0078125,
}


def check_measure_durations(xml_path: str) -> dict[str, int]:
    """Check output MusicXML for underfull/overfull measures vs time signature.

    Returns {"ok": N, "underfull": N, "overfull": N}.
    Uses <type> and <dot> elements (not <duration>) for portability.
    """
    try:
        tree = ET.parse(xml_path)  # noqa: S314
    except ET.ParseError:
        return {"ok": 0, "underfull": 0, "overfull": 0}

    root = tree.getroot()
    ns = ""
    if root.tag.startswith("{"):
        ns = root.tag.split("}")[0] + "}"

    result = {"ok": 0, "underfull": 0, "overfull": 0}

    for part in root.iter(f"{ns}part"):
        beats = 4
        beat_type = 4
        expected_duration = float(beats) / beat_type  # in whole notes

        for measure_elem in part.iter(f"{ns}measure"):
            # Check for time signature changes in this measure
            for attributes in measure_elem.iter(f"{ns}attributes"):
                time_elem = attributes.find(f"{ns}time")
                if time_elem is not None:
                    b = time_elem.find(f"{ns}beats")
                    bt = time_elem.find(f"{ns}beat-type")
                    if b is not None and b.text and bt is not None and bt.text:
                        try:
                            beats = int(b.text)
                            beat_type = int(bt.text)
                            expected_duration = float(beats) / beat_type
                        except ValueError:
                            pass

            # Sum note durations in this measure
            total = 0.0
            for note_elem in measure_elem.iter(f"{ns}note"):
                if note_elem.find(f"{ns}grace") is not None:
                    continue
                # Chords share duration with previous, skip
                if note_elem.find(f"{ns}chord") is not None:
                    continue
                # Forward/backup elements could also affect but we keep it simple
                type_elem = note_elem.find(f"{ns}type")
                if type_elem is None or type_elem.text is None:
                    continue
                base = _TYPE_FRACTIONS.get(type_elem.text, 0.0)
                dots = len(note_elem.findall(f"{ns}dot"))
                dur = base
                dot_val = base
                for _ in range(dots):
                    dot_val /= 2
                    dur += dot_val
                total += dur

            if total == 0:
                continue  # empty or all-grace measure

            tolerance = 0.01
            if abs(total - expected_duration) < tolerance:
                result["ok"] += 1
            elif total < expected_duration - tolerance:
                result["underfull"] += 1
            else:
                result["overfull"] += 1
        break  # first part only

    return result


def diagnose_to_result(
    gt_measures: list[MeasureNotes],
    out_measures: list[MeasureNotes],
    out_xml_path: str | None = None,
) -> DiagnosisResult:
    """Run diagnosis and return structured result (no printing)."""
    gt_by_num = {m.measure_num: m for m in gt_measures}
    out_by_num = {m.measure_num: m for m in out_measures}
    overlap = sorted(set(gt_by_num) & set(out_by_num))

    all_errors: list[ErrorInfo] = []
    perfect = 0

    for num in overlap:
        gt_m = gt_by_num[num]
        out_m = out_by_num[num]
        staves = sorted(set(gt_m.notes_by_staff) | set(out_m.notes_by_staff))
        measure_errors: list[ErrorInfo] = []
        for staff in staves:
            gt_notes = gt_m.notes_by_staff.get(staff, [])
            out_notes = out_m.notes_by_staff.get(staff, [])
            measure_errors.extend(compare_measure_staff(gt_notes, out_notes, num, staff))

        if not measure_errors:
            perfect += 1
        all_errors.extend(measure_errors)

    categories = [
        "missing",
        "extra",
        "octave",
        "accidental",
        "enharmonic",
        "step",
        "rhythm",
        "rest_note_swap",
        "cross_staff",
        "far_pitch",
    ]
    counts: dict[str, int] = dict.fromkeys(categories, 0)
    per_staff: dict[int, int] = {}
    for e in all_errors:
        counts[e.category] = counts.get(e.category, 0) + 1
        per_staff[e.staff] = per_staff.get(e.staff, 0) + 1

    duration_check = {"ok": 0, "underfull": 0, "overfull": 0}
    if out_xml_path:
        duration_check = check_measure_durations(out_xml_path)

    return DiagnosisResult(
        errors=all_errors,
        perfect_measures=perfect,
        total_measures=len(overlap),
        error_counts=counts,
        per_staff_errors=per_staff,
        duration_check=duration_check,
    )


def main() -> None:
    if len(sys.argv) < 3:
        print("Usage: python -m validation.diagnose_musicxml <ground_truth.xml> <output.musicxml>")
        sys.exit(1)

    gt_path = sys.argv[1]
    out_path = sys.argv[2]
    diagnose(gt_path, out_path)


if __name__ == "__main__":
    main()

import json
from collections import defaultdict

import torch

from homr.transformer.configs import default_config
from homr.transformer.vocabulary import EncodedSymbol, Vocabulary, sort_token_chords

vocab = Vocabulary()


def check_token_line(line: EncodedSymbol) -> None:
    if (
        line.rhythm not in vocab.rhythm
        or line.lift not in vocab.lift
        or line.articulation not in vocab.articulation
        or line.pitch not in vocab.pitch
        or line.position not in vocab.position
    ):
        raise ValueError("Invalid symbol " + str(line))

    if not line.is_valid():
        raise ValueError("Invalid combination " + str(line))


def check_token_lines(lines: list[EncodedSymbol]) -> None:
    for line in lines:
        check_token_line(line)


def _symbol_to_sortable(symbol: EncodedSymbol) -> int:
    position = 10000000 if symbol.position == "lower" else 0
    if "note" in symbol.rhythm:
        return (
            vocab.pitch[symbol.pitch] * len(vocab.rhythm) + vocab.rhythm[symbol.rhythm] + position
        )
    if "rest" in symbol.rhythm:
        return 100000 + vocab.rhythm[symbol.rhythm] + position
    return 1000000 + position


def _chord_to_str(chord: list[EncodedSymbol]) -> str:
    sorted_chord = sorted(chord, key=_symbol_to_sortable)
    upper_slurs_ties = set()
    lower_slurs_ties = set()
    annotation_resorted: list[EncodedSymbol] = []
    for symbol in sorted_chord:
        stripped, symbol_stripped = symbol.strip_articulations([], remove_all=True)
        for articulation in stripped:
            if symbol.position == "lower":
                lower_slurs_ties.add(articulation)
            else:
                upper_slurs_ties.add(articulation)
        annotation_resorted.append(symbol_stripped)
    if len(upper_slurs_ties) > 0:
        first_upper = next(
            (idx for idx, s in enumerate(annotation_resorted) if s.position != "lower"), None
        )
        if first_upper is not None:
            annotation_resorted[first_upper] = annotation_resorted[first_upper].add_articulations(
                list(upper_slurs_ties)
            )
    if len(lower_slurs_ties) > 0:
        first_lower = next(
            (idx for idx, s in enumerate(annotation_resorted) if s.position == "lower"), None
        )
        if first_lower is not None:
            annotation_resorted[first_lower] = annotation_resorted[first_lower].add_articulations(
                list(lower_slurs_ties)
            )
    return str.join("&", [str(c) for c in annotation_resorted])


def calc_ratio_of_tuplets(symbols: list[EncodedSymbol]) -> float:
    tuplets = [s for s in symbols if s.is_tuplet()]
    return float(len(tuplets)) / len(symbols)


def token_lines_to_str(symbols: list[EncodedSymbol]) -> str:
    chords = sort_token_chords(symbols)

    chord_strings = [_chord_to_str(c) for c in chords]
    return str.join("\n", chord_strings)


def read_token_lines(lines: list[str]) -> list[EncodedSymbol]:
    result = []
    for line in lines:
        entries = line.split("&")
        for i, entry in enumerate(entries):
            if "tieSlur" in entry:
                continue
            parts = entry.strip().split()
            if len(parts) == 5:
                rhythm, pitch, lift, articulation, position = parts
            else:
                rhythm, pitch, lift, articulation = parts
                position = "upper"
            symbol = EncodedSymbol(rhythm, pitch, lift, articulation, position)
            is_first = i == 0
            if not is_first:
                result.append(EncodedSymbol("chord"))

            result.append(symbol)

    return result


def read_tokens(filepath: str) -> list[EncodedSymbol]:
    with open(filepath, encoding="utf-8") as f:
        lines = f.readlines()
        return read_token_lines(lines)


class DecoderBranches:
    def __init__(
        self,
        rhythms: torch.Tensor,
        pitchs: torch.Tensor,
        lifts: torch.Tensor,
        articulations: torch.Tensor,
        positions: torch.Tensor,
        mask: torch.Tensor,
    ) -> None:
        self.rhythms = rhythms
        self.pitchs = pitchs
        self.lifts = lifts
        self.articulations = articulations
        self.positions = positions
        self.mask = mask


def to_decoder_branches(symbols: list[EncodedSymbol]) -> DecoderBranches:
    nonote_token = default_config.nonote_token
    begin_of_seq = vocab.rhythm["BOS"]
    end_of_seq = vocab.rhythm["EOS"]
    rhythms = [begin_of_seq]
    pitchs = [nonote_token]
    lifts = [nonote_token]
    articulations = [nonote_token]
    position = [nonote_token]
    mask = [True]
    for symbol in symbols:
        rhythms.append(vocab.rhythm[symbol.rhythm])
        pitchs.append(vocab.pitch[symbol.pitch])
        lifts.append(vocab.lift[symbol.lift])
        articulations.append(vocab.articulation[symbol.articulation])
        position.append(vocab.position[symbol.position])
        mask.append(True)

    rhythms.append(end_of_seq)
    pitchs.append(nonote_token)
    lifts.append(nonote_token)
    articulations.append(nonote_token)
    position.append(nonote_token)
    mask.append(True)

    while len(rhythms) < default_config.max_seq_len:
        rhythms.append(default_config.pad_token)
        pitchs.append(nonote_token)
        lifts.append(nonote_token)
        articulations.append(nonote_token)
        position.append(nonote_token)
        mask.append(False)

    return DecoderBranches(
        rhythms=torch.tensor(rhythms),
        lifts=torch.tensor(lifts),
        articulations=torch.tensor(articulations),
        pitchs=torch.tensor(pitchs),
        positions=torch.tensor(position),
        mask=torch.tensor(mask),
    )


class VocabularyStats:
    def __init__(self) -> None:
        self.rhythm: dict[str, int] = defaultdict(int)
        self.lift: dict[str, int] = defaultdict(int)
        self.articulation: dict[str, int] = defaultdict(int)
        self.pitch: dict[str, int] = defaultdict(int)
        self.max_seq_len = 0

    def add_lines(self, lines: list[EncodedSymbol]) -> None:
        for line in lines:
            self.rhythm[line.rhythm] += 1
            self.lift[line.lift] += 1
            self.articulation[line.articulation] += 1
            self.pitch[line.pitch] += 1
        self.max_seq_len = max(self.max_seq_len, len(lines))

    def __str__(self) -> str:
        lines = [
            json.dumps(self.rhythm, indent=2, sort_keys=True),
            json.dumps(self.lift, indent=2, sort_keys=True),
            json.dumps(self.articulation, indent=2, sort_keys=True),
            json.dumps(self.pitch, indent=2, sort_keys=True),
            f"max_seq_len={self.max_seq_len}",
        ]
        return str.join("\n", lines)

    def __repr__(self) -> str:
        return str(self)


if __name__ == "__main__":
    import glob
    import os
    import sys

    from homr.simple_logging import eprint

    stats = VocabularyStats()
    errors: set[str] = set()
    i = 0
    if len(sys.argv) > 1:
        files = []
        for index_path in sys.argv[1:]:
            index_file = open(index_path)
            index_lines = index_file.readlines()
            index_file.close()
            files.extend([line.strip().split(",")[1] for line in index_lines])
    else:
        files = glob.glob(os.path.join("datasets", "**", "**.tokens"), recursive=True)

    for file in files:
        try:
            tokens = read_tokens(file)
            stats.add_lines(tokens)
            check_token_lines(tokens)
            i += 1
            if i % 1000 == 0:
                eprint(i, len(errors))
        except Exception as e:
            eprint("======", file, "======")
            eprint(e)
            errors.add(file)

    eprint("Stats", stats)
    if len(errors) > 0:
        eprint("errors", errors)

